# Since we need to generate all books, let me create a function that generates remaining chapters

def generate_remaining_chapters(book_name, total_chapters, existing_chapters):
    """Generate key verses for chapters that don't have specific verses defined"""
    chapters = []
    for ch in range(1, total_chapters + 1):
        if book_name in KEY_VERSES and ch in KEY_VERSES[book_name]:
            chapters.append({"chapter": ch, "verses": KEY_VERSES[book_name][ch]})
        else:
            # Generate a placeholder key verse
            chapters.append({"chapter": ch, "verses": [{"verse": 1, "text": f"Chapter {ch} of {book_name}."}]})
    return chapters

