def main():
    output_dir = os.path.join(os.path.dirname(__file__), "app", "src", "main", "assets", "bible")

    for book in BOOKS:
        book_name = book["name"]
        file_name = book["file"]
        total_chapters = book["chapters"]

        # Read existing file
        file_path = os.path.join(output_dir, file_name)
        existing_chapters = 0

        if os.path.exists(file_path):
            with open(file_path, "r", encoding="utf-8") as f:
                data = json.load(f)
                existing_chapters = len(data.get("chapters", []))

        # Skip if already complete
        if existing_chapters >= total_chapters:
            print(f"✓ {book_name}: {existing_chapters}/{total_chapters} chapters - OK")
            continue

        print(f"→ {book_name}: {existing_chapters}/{total_chapters} chapters - Completing...")

        # Generate complete chapters
        chapters = generate_remaining_chapters(book_name, total_chapters, existing_chapters)

        book_data = {
            "book": book_name,
            "chapters": chapters
        }

        # Write to file
        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(book_data, f, ensure_ascii=False)

        print(f"  Saved {total_chapters} chapters to {file_name}")

if __name__ == "__main__":
    main()

